.form-item-operation {
  display: flex;
  flex: 1;
}

.item-info {
  display: inline-flex;
  width: 100%;
  align-items: center;
}

.active-item {
  border: 1px dashed var(--star-horse-style);
}

.design-star-horse {
  width: 100%;
  margin-top: 15px;
  display: flex;
  justify-content: center;
  vertical-align: middle;
  align-items: center;
  min-height: 50px;
  z-index: 0;
}

.field-item {
  position: relative;
  width: 100%;
  height: 100%;
  vertical-align: middle;
  align-items: center;

  .bare-item {
    width: 100%;
    height: 100%;
  }


  .el-form-item {
    margin-bottom: 1px;
  }

  .field-action {
    position: absolute;
    //bottom: -25px;
    top: 0;
    transform: translate(0, -100%);
    right: 0;
    align-items: center;
    background: var(--star-horse-style);
    z-index: 99;
    display: flex;

    .svg-icon {
      font-size: 14px;
      color: var(--star-horse-white);
      margin: 4px;
      cursor: pointer;
    }
  }

  .drag-handler {
    position: absolute;
    top: 0;
    left: 0;
    display: flex;
    align-items: center;
    background: var(--star-horse-style);
    z-index: 9999999;
    transform: translate(0, -100%);

    .svg-icon {
      font-size: 12px;
      font-style: normal;
      color: var(--star-horse-style);
      margin: 4px;

      &:first-child {
        cursor: move;
      }

      &:last-child {
        cursor: pointer;
      }
    }

    /*   &:hover {
         opacity: 1;
         background: var(--star-horse-style);
       }*/
  }
}

.field-action,
.drag-handler {
  :deep(.svg-icon) {
    margin-left: 0;
    margin-right: 0;
  }
}

.drag-handler {
  padding-right: 10px;
  font-size: 13px;
}

.el-form-item {
  //margin-bottom: 0 !important;
  //margin-bottom: 6px;
  //margin-top: 2px;
  position: relative;

  :deep(.el-form-item__label) {
    white-space: nowrap;
    text-overflow: ellipsis;
  }


  span.custom-label i {
    margin: 0 3px;
  }

  /* 隐藏Chrome浏览器中el-input数字输入框右侧的上下调整小箭头 */
  :deep(.hide-spin-button) input::-webkit-outer-spin-button,
  :deep(.hide-spin-button) input::-webkit-inner-spin-button {
    -webkit-appearance: none !important;
  }

  /* 隐藏Firefox浏览器中el-input数字输入框右侧的上下调整小箭头 */
  :deep(.hide-spin-button) input[type="number"] {
    -moz-appearance: textfield;
  }
}

.required :deep(.el-form-item__label)::before {
  content: "*";
  color: #f56c6c;
  margin-right: 4px;
}

.static-content-item {
  min-height: 20px;
  display: flex; /* 垂直居中 */
  align-items: center; /* 垂直居中 */
  :deep(.el-divider--horizontal) {
    margin: 0;
  }
}

.el-form-item.selected,
.static-content-item.selected {
  outline: 2px solid var(--star-horse-style);
